import { createClient } from '@/lib/supabase/server'
import { redirect } from 'next/navigation'
import { Navbar } from '@/components/Navbar'
import { PostCard } from '@/components/PostCard'
import { Bookmark, Globe, Database, ExternalLink, Trash2, Quote, Clock } from 'lucide-react'
import Link from 'next/link'

export const metadata = {
    title: 'Saved | Syrealize',
    description: 'Your saved posts and web references',
}

async function getSavedContent(userId: string, supabase: any) {
    // Get bookmarked posts
    const { data: bookmarks, error: bookmarksError } = await supabase
        .from('bookmarks')
        .select(`
            id,
            created_at,
            post:posts(
                id,
                title,
                content,
                tags,
                status,
                created_at,
                updated_at,
                author_id,
                author:users!posts_author_id_fkey(id, name, email)
            )
        `)
        .eq('user_id', userId)
        .order('created_at', { ascending: false })

    if (bookmarksError) {
        console.error('Error fetching bookmarks:', bookmarksError.message)
    }

    // Get saved web references
    const { data: references, error: referencesError } = await supabase
        .from('saved_references')
        .select('*')
        .eq('user_id', userId)
        .order('created_at', { ascending: false })

    if (referencesError) {
        console.error('Error fetching references:', referencesError.message)
    }

    return { bookmarks: bookmarks || [], references: references || [] }
}

export default async function SavedPage({
    searchParams
}: {
    searchParams: Promise<{ tab?: string }>
}) {
    const params = await searchParams
    const supabase = await createClient()

    const { data: { user } } = await supabase.auth.getUser()

    if (!user) {
        redirect('/login')
    }

    const { bookmarks, references } = await getSavedContent(user.id, supabase)

    const savedPosts = bookmarks
        .filter((b: any) => b.post)
        .map((b: any) => ({
            ...b.post,
            comment_count: 0,
            citation_count: 0,
            license: null,
            forked_from_id: null
        }))

    const activeTab = params.tab || 'posts'

    return (
        <div className="min-h-screen flex flex-col bg-background dark:bg-dark-bg">
            <Navbar user={user} />

            <main className="flex-1 section pt-20 md:pt-24">
                <div className="container-custom max-w-4xl">
                    {/* Header */}
                    <div className="flex items-center gap-3 mb-6">
                        <div className="p-2 rounded-lg bg-gray-100 dark:bg-dark-surface">
                            <Bookmark className="w-5 h-5 text-text dark:text-dark-text" />
                        </div>
                        <div>
                            <h1 className="text-2xl font-display font-semibold text-primary dark:text-dark-text">
                                Saved
                            </h1>
                            <p className="text-sm text-text-light dark:text-dark-text-muted">
                                {savedPosts.length} posts · {references.length} web references
                            </p>
                        </div>
                    </div>

                    {/* Tabs */}
                    <div className="flex items-center gap-1 p-1 bg-gray-100 dark:bg-dark-border rounded-lg mb-6 w-fit">
                        <Link
                            href="/saved?tab=posts"
                            className={`flex items-center gap-1.5 px-4 py-2 rounded-md text-sm font-medium transition-colors ${activeTab === 'posts'
                                    ? 'bg-white dark:bg-dark-surface text-primary shadow-sm'
                                    : 'text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-200'
                                }`}
                        >
                            <Database className="w-4 h-4" />
                            Posts
                            {savedPosts.length > 0 && (
                                <span className="px-1.5 py-0.5 text-xs bg-primary/10 text-primary rounded-full">
                                    {savedPosts.length}
                                </span>
                            )}
                        </Link>
                        <Link
                            href="/saved?tab=references"
                            className={`flex items-center gap-1.5 px-4 py-2 rounded-md text-sm font-medium transition-colors ${activeTab === 'references'
                                    ? 'bg-white dark:bg-dark-surface text-blue-600 shadow-sm'
                                    : 'text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-200'
                                }`}
                        >
                            <Globe className="w-4 h-4" />
                            Web References
                            {references.length > 0 && (
                                <span className="px-1.5 py-0.5 text-xs bg-blue-50 dark:bg-blue-900/20 text-blue-600 rounded-full">
                                    {references.length}
                                </span>
                            )}
                        </Link>
                    </div>

                    {/* Posts Tab */}
                    {activeTab === 'posts' && (
                        <>
                            {savedPosts.length > 0 ? (
                                <div className="space-y-6">
                                    {savedPosts.map((post: any) => (
                                        <PostCard key={post.id} post={post} />
                                    ))}
                                </div>
                            ) : (
                                <div className="text-center py-16">
                                    <Database className="w-12 h-12 mx-auto text-gray-300 dark:text-dark-border mb-4" />
                                    <h2 className="text-lg font-medium text-text dark:text-dark-text mb-2">
                                        No saved posts yet
                                    </h2>
                                    <p className="text-text-light dark:text-dark-text-muted mb-6">
                                        Click the bookmark icon on any post to save it for later.
                                    </p>
                                    <Link href="/feed" className="btn btn-primary">
                                        Explore Posts
                                    </Link>
                                </div>
                            )}
                        </>
                    )}

                    {/* Web References Tab */}
                    {activeTab === 'references' && (
                        <>
                            {references.length > 0 ? (
                                <div className="space-y-4">
                                    {references.map((ref: any) => (
                                        <div
                                            key={ref.id}
                                            className="bg-white dark:bg-dark-surface rounded-xl border border-blue-100 dark:border-blue-900/30 p-5 hover:shadow-md transition-all"
                                        >
                                            <div className="flex items-start gap-3">
                                                <div className="shrink-0 w-8 h-8 rounded-lg bg-blue-50 dark:bg-blue-900/20 flex items-center justify-center">
                                                    <Globe className="w-4 h-4 text-blue-500" />
                                                </div>
                                                <div className="flex-1 min-w-0">
                                                    <div className="flex items-center gap-2">
                                                        <a
                                                            href={ref.url}
                                                            target="_blank"
                                                            rel="noopener noreferrer"
                                                            className="font-medium text-gray-900 dark:text-gray-100 hover:text-blue-600 transition-colors line-clamp-1"
                                                        >
                                                            {ref.title}
                                                        </a>
                                                        <span className="text-xs px-1.5 py-0.5 bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 rounded font-medium">
                                                            Web
                                                        </span>
                                                    </div>
                                                    {ref.snippet && (
                                                        <p className="text-sm text-gray-600 dark:text-gray-400 line-clamp-2 mt-1">
                                                            {ref.snippet}
                                                        </p>
                                                    )}
                                                    <div className="flex items-center gap-3 mt-2 text-xs text-gray-500 dark:text-gray-400">
                                                        <span className="flex items-center gap-1">
                                                            <Globe className="w-3 h-3 text-blue-500" />
                                                            {ref.source || 'Web'}
                                                        </span>
                                                        <span className="flex items-center gap-1">
                                                            <Clock className="w-3 h-3" />
                                                            {new Date(ref.created_at).toLocaleDateString()}
                                                        </span>
                                                    </div>

                                                    {/* Action buttons */}
                                                    <div className="flex items-center gap-2 mt-3 pt-3 border-t border-gray-100 dark:border-dark-border">
                                                        <a
                                                            href={ref.url}
                                                            target="_blank"
                                                            rel="noopener noreferrer"
                                                            className="flex items-center gap-1.5 px-2.5 py-1.5 text-xs rounded-md text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-dark-border transition-colors"
                                                        >
                                                            <ExternalLink className="w-3.5 h-3.5" />
                                                            Open
                                                        </a>
                                                        {ref.citation && (
                                                            <button
                                                                onClick={() => navigator.clipboard.writeText(ref.citation)}
                                                                className="flex items-center gap-1.5 px-2.5 py-1.5 text-xs rounded-md text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-dark-border transition-colors"
                                                            >
                                                                <Quote className="w-3.5 h-3.5" />
                                                                Copy Citation
                                                            </button>
                                                        )}
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <div className="text-center py-16">
                                    <Globe className="w-12 h-12 mx-auto text-blue-200 dark:text-blue-900/50 mb-4" />
                                    <h2 className="text-lg font-medium text-text dark:text-dark-text mb-2">
                                        No web references yet
                                    </h2>
                                    <p className="text-text-light dark:text-dark-text-muted mb-6">
                                        Save web search results from the Research Lab Search Engine.
                                    </p>
                                    <Link href="/research-lab/search" className="btn btn-primary">
                                        Go to Search Engine
                                    </Link>
                                </div>
                            )}
                        </>
                    )}
                </div>
            </main>
        </div>
    )
}
